// ── CRUD TRANSAÇÕES via API ────────────────────────────────────────────────
function adicionarTransacao(dados) {
  fetch('/api/financeiro/transacoes', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(dados)
  })
  .then(function(r) { return r.json(); })
  .then(function(res) {
    if (res.ok) {
      dados.id = res.id;
      TRANSACOES.push(dados);
      atualizarTudo();
    }
  })
  .catch(function(e) { console.error('Erro ao adicionar transação:', e); });
}

function editarTransacao(id, campos) {
  fetch('/api/financeiro/transacoes/' + id, {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(campos)
  }).catch(function(e) { console.error('Erro ao editar transação:', e); });
}

function deletarTransacao(id) {
  fetch('/api/financeiro/transacoes/' + id, { method: 'DELETE' })
    .catch(function(e) { console.error('Erro ao deletar transação:', e); });
}

// ── CARREGAR DADOS DA API ──────────────────────────────────────────────────
function carregarDados() {
  var container = document.getElementById('fin-pane-visao-geral');
  if (container) container.innerHTML = '<p style="text-align:center;padding:2rem;color:var(--cyan)">Carregando...</p>';

  Promise.all([
    fetch('/api/financeiro/transacoes').then(function(r){ return r.json(); }),
    fetch('/api/financeiro/raiox').then(function(r){ return r.json(); })
  ]).then(function(resultados) {
    TRANSACOES = resultados[0];
    var raiox   = resultados[1];
    if (raiox && raiox.entradas) RAIOX = raiox;
    if (container) container.innerHTML = '';
    atualizarTudo();
    renderRaioX();
  }).catch(function(e) {
    console.error('Erro ao carregar dados financeiros:', e);
    if (container) container.innerHTML = '<p style="text-align:center;padding:2rem;color:#ff6b6b">Erro ao carregar dados. Verifique conexão.</p>';
  });
}

